#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        ll n,m;        cin>>n>>m;        vector<vector<ll>> a(n,vector<ll>(m));        for(int i = 0; i < n; i++){            string row;            cin >> row;            for(int j = 0; j < m; j++){                a[i][j] = row[j] - '0';            }        }        int layer = (min(n, m) + 1) / 2;        int stc=0;        int endc=m-1;        int str=0;        int endr=n-1;        string target="1543";        ll ans=0;        while(layer--){            string s="";            for(int i=stc;i<=endc;i++){                s += char(a[str][i] + '0');            }            for(int i=str+1;i<=endr;i++){                s += char(a[i][endc] + '0');            }            if(str < endr){                for(int i=endc-1;i>=stc;i--){                    s += char(a[endr][i] + '0');                }            }            if(stc < endc){                for(int i=endr-1;i>=str+1;i--){                    s += char(a[i][stc] + '0');                }            }            str++;            endr--;            stc++;            endc--;            s+=s.substr(0,min(3,(int)s.size()));            for(int i = 0; i + 3 < (int)s.size(); i++){                if(s.substr(i,4) == target) ans++;            }        }        cout<<ans<<endl;    }}